import java.awt.image.*;
public class Grayscale {
    public static int toGray(int rgb) {
        int r = (rgb >> 16) & 0xFF;
        int g = (rgb >>  8) & 0xFF;
        int b =  rgb        & 0xFF;
        int avg = (r + g + b) / 3;
        return (avg << 16) | (avg << 8) | avg;
    }

    public static void main(String[] args) {
        int pixel = 0x0060C0;  // r=0, g=96, b=192
        int gray = toGray(pixel);
        int channel = gray & 0xFF;  // all three channels equal
        System.out.println(channel);
    }
}
